+        let dbg = format!("{:?}", d);
+        assert!(dbg.contains("Normal"));
+
+        let d2 = d.clone();
+        assert_eq!(d, d2);
+
+        let d3 = DownReason::Error("oops".into());
+        assert_ne!(d, d3);
+    }
 }

